    push(item: string): void {
        this.heap.push(item);
        this.bubbleUp(this.heap.length - 1);
    }

    pop(): string {
        if (this.heap.length === 1) {
            return this.heap.pop()!;
        }
        const top = this.heap[0];
        this.heap[0] = this.heap[this.heap.length - 1];
        this.heap.pop();
        this.bubbleDown(0);
        return top;
